LAYER
  NAME "mapa_susceptibilidad_huaycos"
  GROUP "Riesgos"
  STATUS off
  DATA "archivos/raster/mapa_susceptibilidad_huaycos.img"
  TYPE RASTER
  TRANSPARENCY 100
  DUMP true
  HEADER   "plantillas/inicio.html"
  TEMPLATE "plantillas/raster.html"
  FOOTER   "plantillas/fin.html" 
  PROJECTION
	"init=epsg:4326"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Riesgos"
	"queryable" "true"
	"wms_metadataurl_type" "TC211"
	"wms_title" "Mapa de susceptibilidad a huaycos Región Cusco"
	"wms_abstract" "Mapa de susceptibilidad a huaycos Región Cusco - Copyright © Centro de Estudios y Prevención de Desastres - PREDES :: http://www.predes.org.pe/, Publicado para el Programa de Adaptación al Cambio Climático  - PACC Perú 2013 :: http://www.paccperu.org.pe"
	"wms_dataurl_href" "../descargar/mapa_susceptibilidad_huaycos.rar" 
	"autor" "© PREDES (Mayo 2011) - PACC Perú"
	"wms_extent" "-73.9924109055233 -15.4602340741746 -70.3444109055233 -11.2137340741746"
	"wms_srs" "EPSG:4326"
